import { Component, Event, EventEmitter, Prop, Host, h } from '@stencil/core';

/**
 * Sliding panel is a layout element that reveals/hides content relevent to the contents of a page.
 */

@Component({
  tag: "kds-sliding-panel",
  styleUrl: "./kds-sliding-panel.css",
  shadow: false
})
export class KdsSlidingPanel {
  /** Positions to the left or right of content. */
  @Prop() readonly align: "left" | "right" = "left";

  /** Applies a fixed position. */
  @Prop() readonly overlap: boolean = false;

  /** Determines if panel is open. */
  @Prop({ mutable: true }) open: boolean = false;

  /** Defines title text. */
  @Prop() readonly panelTitle!: string;

  /** Defines icon. */
  @Prop() readonly icon: string = "kds-icon-filters";

  /** Defines the icon used to close the sliding panel. */
  @Prop() readonly closeIcon: string = "kds-icon-close";

  /** Determines if badge displayed and what its value is. */
  @Prop() readonly badgeValue: number = 0;

  /** Sets aria label when badge is defined, i.e., "filters selected" or "messages unread". */
  @Prop() readonly badgeLabel: string;

  /** Defines the custom width of the open panel in `rem` units. */
  @Prop() readonly panelWidth: number;

  /** Applies a hidden attribute to the component if true. */
  @Prop() readonly hideCollapsedPanel: boolean = false;

  /** Defines the heading level in relation to the layout it's being placed. */
  @Prop() readonly headingLevel: "h1" | "h2" | "h3" | "h4" | "h5" | "h6" = "h3";

  validateBadgeLabel() {
    if (this.badgeValue > 0 && !this.badgeLabel) {
      console.error(
        `🚨 Accessibility No-No: You must set a badge-label on kds-sliding-panel if badge-value is set.`
      );
    }
  }

  /** Toggles open/close state. */
  @Event() slidingPanelToggled: EventEmitter<any>;

  togglePanel() {
    this.open = !this.open;
    this.slidingPanelToggled.emit({ open: this.open });
  }

  render() {
    const HeadingTag = this.headingLevel;
    const Icon = this.icon;
    const CloseIcon = this.closeIcon;
    this.validateBadgeLabel();

    return (
      <Host
        class={{
          "kds-SlidingPanel": true,
          open: this.open,
          [`kds-SlidingPanel--${this.align}`]: true,
          "kds-SlidingPanel--absolute": this.overlap
        }}
        hidden={this.hideCollapsedPanel && !this.open}
        style={
          this.open && this.panelWidth && { width: `${this.panelWidth}rem` }
        }
        role='group'
        aria-label={this.panelTitle}
      >
        <header
          class={{
            "kds-SlidingPanel-header": true,
            "border-b border-default-300": this.open
          }}
        >
          {this.open && (
            <HeadingTag
              class='kds-SlidingPanel-heading kds-Paragraph--m'
              role='heading'
            >
              {this.panelTitle}
            </HeadingTag>
          )}

          <kds-button
            button-class={!this.open && this.badgeValue > 0 ? 'kds-Button--hasIconOnly' : ''}
            class={{
              "kds-SlidingPanel-headerButton": true,
              "kds-SlidingPanel-headerButton--right": this.align === "right",
              "kds-SlidingPanel-headerButton--left": this.align !== "right"
            }}
            palette='brand'
            kind='prominent'
            variant='fill'
            inverse
            onClick={() => this.togglePanel()}
            inner-aria-label={`${this.panelTitle} ${
              this.badgeValue ? this.badgeValue : ""
            } ${this.badgeLabel ? this.badgeLabel : ""}`}
            inner-aria-expanded={`${this.open}`}
          >
            {!this.open && this.badgeValue > 0 && (
              <kds-badge
                class={{
                  "kds-SlidingPanel-ButtonIcon": true,
                  "mr-8": this.align === "right"
                }}
                count={this.badgeValue}
              >
                <Icon size='m' />
              </kds-badge>
            )}

            {!this.open && this.badgeValue === 0 && (
              <Icon class='kds-SlidingPanel-ButtonIcon' size='m' />
            )}

            {this.open && (
              <CloseIcon class='kds-SlidingPanel-ButtonIcon' size='m' />
            )}
          </kds-button>
        </header>
        <div class='kds-SlidingPanel-body' hidden={!this.open}>
          <slot />
        </div>
      </Host>
    );
  }
}
